scwin._getInputComp = function (id) {
  if (!id || id === "") return null;
  try {
    return WebSquare.util.getComponentById(id);
  } catch (e) {
    return null;
  }
};
scwin._getInputValue = function (id) {
  let comp = scwin._getInputComp(id);
  if (comp) return comp.getValue();
  return "";
};
scwin._setInputValue = function (id, val) {
  let comp = scwin._getInputComp(id);
  if (comp) comp.setValue(val);
};
scwin.onpageload = function () {
  $c.gus.cfDisableAllBtn($p);
  $c.gus.cfDisableObjects($p, [btn_addRow, btn_cancelRow]);
};
scwin.onUdcCompleted = function () {
  ed_bilgLoofcCd.setFocus();
};
scwin.f_GetDataSet = async function (condition, row) {
  if (condition == "LINE_CON") {
    dma_linelist_con.set("bilgLoofcCd", ed_bilgLoofcCd.getValue());
    dma_linelist_con.set("bilgComnCdKnd", scwin.billtitle);
    sbm_linelist_retrieve.action = "/ds.fs.bilg.bilgcomncdmgnt.RetrieveBillingComnCdLineListCMD.do";
    await $c.sbm.execute($p, sbm_linelist_retrieve);
  } else if (condition == "BILGCOMNCD_CON") {
    dma_billtitle_con.set("bilgLoofcCd", ds_linelist.getCellData(0, "bilgLoofcCd"));
    dma_billtitle_con.set("lineCd", ds_linelist.getCellData(row - 1, "lineCd"));
    dma_billtitle_con.set("bilgComnCdKnd", scwin.billtitle);
    if (row == "1") {
      sbm_billtitle_retrieve.action = "/ds.fs.bilg.bilgcomncdmgnt.RetrieveBillTitleListCMD.do";
    } else {
      sbm_billtitle_retrieve.action = "/ds.fs.bilg.bilgcomncdmgnt.RetrieveBillTitleListCMD.do";
    }
    await $c.sbm.execute($p, sbm_billtitle_retrieve);
  }
};
scwin.f_Retrieve = async function () {
  let chk = await $c.gus.cfValidate($p, [ed_bilgLoofcCd]);
  if (!chk) return;
  await scwin.f_GetDataSet("LINE_CON");
};
scwin.btn_retrieve_onclick = function (e) {
  scwin.f_Retrieve();
};
scwin.f_Save = async function () {
  let chk = await $c.gus.cfValidate($p, [gr_line]);
  if (!chk) return;
  if (!(await scwin.f_CheckMandatory())) return;
  let confirmChk = await $c.gus.cfConfirmMsg($p, MSG_CM_CRM_001);
  if (!confirmChk) return;
  let rowPos = ds_linelist.getRowPosition();
  for (let j = 0; j < ds_billtitle.getRowCount(); j++) {
    ds_billtitle.setCellData(j, "bilgLoofcCd", ds_linelist.getCellData(0, "bilgLoofcCd"));
    ds_billtitle.setCellData(j, "lineCd", ds_linelist.getCellData(rowPos, "lineCd"));
    let ids = scwin.titleInputIds[j];
    if (ids) {
      ds_billtitle.setCellData(j, "title1", scwin._getInputValue(ids[0]));
      ds_billtitle.setCellData(j, "title2", scwin._getInputValue(ids[1]));
      ds_billtitle.setCellData(j, "title3", scwin._getInputValue(ids[2]));
      ds_billtitle.setCellData(j, "title4", scwin._getInputValue(ids[3]));
      ds_billtitle.setCellData(j, "billAggrNm", scwin._getInputValue(ids[4]));
    }
  }
  scwin.delflag = "";
  if (scwin.addflag == "REG") {
    sbm_billtitle_save.action = "/ds.fs.bilg.bilgcomncdmgnt.RegistBillTitleCMD.do";
  } else if (scwin.addflag == "" || scwin.addflag == "MOD") {
    sbm_billtitle_save.action = "/ds.fs.bilg.bilgcomncdmgnt.UpdateBillTitleCMD.do";
  }
  await $c.sbm.execute($p, sbm_billtitle_save);
};
scwin.btn_save_onclick = function (e) {
  scwin.f_Save();
};
scwin.f_AddRow = async function () {
  ds_linelist.insertRow();
  scwin.f_Popup();
  await scwin.f_GetDataSet("BILGCOMNCD_CON", "1");
  let rowPos = ds_linelist.getRowPosition();
  if (ds_linelist.getRowStatus(rowPos) == "C") {
    scwin.addflag = "REG";
  }
};
scwin.f_addRow = function () {
  scwin.f_AddRow();
};
scwin.f_Delete = async function () {
  let rowPos = ds_linelist.getRowPosition();
  if (ds_linelist.getRowStatus(rowPos) == "C") {
    await $c.gus.cfAlertMsg($p, scwin.MSG_FS_WRN_004);
    return;
  } else {
    if (ds_linelist.getCellData(rowPos, "lineCd") == "0000") {
      await $c.gus.cfAlertMsg($p, scwin.MSG_FS_WRN_005);
      return;
    }
    let confirmChk = await $c.gus.cfConfirmMsg($p, MSG_CM_CRM_004);
    if (confirmChk == true) {
      ds_linelist.removeRow(rowPos);
      let btRowPos = ds_billtitle.getRowPosition();
      ds_billtitle.removeRow(btRowPos);
      scwin.delflag = "DEL";
      sbm_billtitle_save.action = "/ds.fs.bilg.bilgcomncdmgnt.DeleteBillTitleCMD.do";
      await $c.sbm.execute($p, sbm_billtitle_save);
      await scwin.f_Retrieve();
    }
  }
};
scwin.btn_del_onclick = function (e) {
  scwin.f_Delete();
};
scwin.f_Editable = function (edit) {
  if (edit == "true") {
    gr_line.setColumnReadOnly("lineCd", false);
    gr_line.setColumnReadOnly("lineNm", true);
  } else {
    gr_line.setColumnReadOnly("lineCd", true);
    gr_line.setColumnReadOnly("lineNm", true);
  }
};
scwin.f_CheckMandatory = async function () {
  for (let i = 0; i < ds_billtitle.getRowCount(); i++) {
    let ids = scwin.titleInputIds[i];
    if (!ids) continue;
    if (ds_billtitle.getCellData(i, "title1").trim().length > 1) {
      if (scwin._getInputValue(ids[0]).trim().length < 1) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["TITLE"]);
        let comp = scwin._getInputComp(ids[0]);
        if (comp) comp.setFocus();
        return false;
      }
    }
    if (ds_billtitle.getCellData(i, "title2").trim().length > 1) {
      if (scwin._getInputValue(ids[1]).trim().length < 1) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["TITLE"]);
        let comp = scwin._getInputComp(ids[1]);
        if (comp) comp.setFocus();
        return false;
      }
    }
    if (ds_billtitle.getCellData(i, "title3").trim().length > 1) {
      if (scwin._getInputValue(ids[2]).trim().length < 1) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["TITLE"]);
        let comp = scwin._getInputComp(ids[2]);
        if (comp) comp.setFocus();
        return false;
      }
    }
    if (ds_billtitle.getCellData(i, "title4").trim().length > 1) {
      if (scwin._getInputValue(ids[3]).trim().length < 1) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["TITLE"]);
        let comp = scwin._getInputComp(ids[3]);
        if (comp) comp.setFocus();
        return false;
      }
    }
    if (ds_billtitle.getCellData(i, "billAggrNm").trim().length > 1) {
      if (scwin._getInputValue(ids[4]).trim().length < 1) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["집계표 TITLE"]);
        let comp = scwin._getInputComp(ids[4]);
        if (comp) comp.setFocus();
        return false;
      }
    }
  }
  return true;
};
scwin.f_Cancel = function () {
  ds_linelist.undoAll();
  scwin.addflag = "MOD";
};
scwin.f_cancelRow = function () {
  scwin.f_Cancel();
};
scwin.f_Popup = function () {
  let rtnList = [];
  let pCode = "";
  let pName = "";
  rtnList = $c.gus.cfCommonPopUp($p, 'retrieveLineInfo', pCode, pName, 'F', null, null, null, null, null, null, null, null, null, null, 'F', null);
  if (rtnList != null && rtnList[0] != "N/A") {
    let rowPos = ds_linelist.getRowPosition();
    ds_linelist.setCellData(rowPos, "lineCd", rtnList[0]);
    ds_linelist.setCellData(rowPos, "lineNm", rtnList[1]);
  }
};
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  let rtnList = [];
  switch (disGubun) {
    case 1:
      rtnList = $c.gus.cfCommonPopUp($p, 'retrieveOpDeptCdInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_bilgLoofcCd, txt_bilgLoofcNm);
      break;
    default:
      break;
  }
};
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) return;
  $c.gus.cfClearPairObj($p, pairObj);
  let pVal = $c.gus.cfGetValue($p, inObj);
  if (isCode == null || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  } else {
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};
scwin.udc_bilgLoofc_onblurCode = function () {
  scwin.f_chkOpenCommonPopUp(ed_bilgLoofcCd, txt_bilgLoofcNm, 1);
};
scwin.f_SetBilltitleToScreen = function () {
  for (let i = 0; i < ds_billtitle.getRowCount(); i++) {
    let ids = scwin.titleInputIds[i];
    if (!ids) continue;
    scwin._setInputValue(ids[0], ds_billtitle.getCellData(i, "title1"));
    scwin._setInputValue(ids[1], ds_billtitle.getCellData(i, "title2"));
    scwin._setInputValue(ids[2], ds_billtitle.getCellData(i, "title3"));
    scwin._setInputValue(ids[3], ds_billtitle.getCellData(i, "title4"));
    scwin._setInputValue(ids[4], ds_billtitle.getCellData(i, "billAggrNm"));
  }
};
scwin.f_ClearTitleInputs = function () {
  for (let i = 0; i < scwin.titleInputIds.length; i++) {
    let ids = scwin.titleInputIds[i];
    for (let k = 0; k < ids.length; k++) {
      scwin._setInputValue(ids[k], "");
    }
  }
};
scwin.sbm_linelist_retrieve_submitdone = async function (e) {
  let rowcnt = ds_linelist.getRowCount();
  // TODO: cfShowTotalRows equivalent
  if (rowcnt == 0) {
    $c.gus.cfInitObjects($p, []);
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    $c.gus.cfDisableAllBtn($p);
    $c.gus.cfDisableObjects($p, [btn_addRow, btn_cancelRow]);
  } else {
    $c.gus.cfEnableAllBtn($p);
    $c.gus.cfEnableObjects($p, [btn_addRow, btn_cancelRow]);
    await scwin.f_GetDataSet("BILGCOMNCD_CON", "1");
    scwin.f_Editable("false");
  }
};
scwin.sbm_linelist_retrieve_submiterror = function (e) {
  $c.gus.cfShowError($p, e);
};
scwin.sbm_billtitle_retrieve_submitdone = function (e) {
  scwin.f_SetBilltitleToScreen();
};
scwin.sbm_billtitle_retrieve_submiterror = function (e) {
  $c.gus.cfShowError($p, e);
};
scwin.sbm_billtitle_save_submitdone = async function (e) {
  scwin.addflag = "MOD";
  if (scwin.delflag == "DEL") {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_004);
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001);
  }
};
scwin.sbm_billtitle_save_submiterror = function (e) {
  $c.gus.cfShowError($p, e);
};
scwin.ds_linelist_onrowpositionchange = async function (info) {
  let row = ds_linelist.getRowPosition();
  if (row >= 0) {
    if (ds_linelist.getRowStatus(row) != "C") {
      await scwin.f_GetDataSet("BILGCOMNCD_CON", row + 1);
      scwin.f_Editable("false");
      scwin.addflag = "MOD";
    } else {
      scwin.f_Editable("true");
      scwin.addflag = "REG";
    }
  }
};
scwin.ds_linelist_canrowpositionchange = async function (info) {
  let rowPos = ds_linelist.getRowPosition();
  if (ds_linelist.getRowStatus(rowPos) == "C") {
    let chk = await $c.win.confirm($p, "저장하지 않은 데이타를 취소하시겠습니까?");
    if (chk == true) {
      ds_linelist.undoAll();
    } else {
      return false;
    }
  }
  return true;
};
scwin.gr_line_ontextimageclick = function (rowIndex, columnIndex) {
  scwin.f_Popup();
};
